{% comment %}
  Bundle Banner - Image ajustée
  Usage: {% render 'bundle-banner' %}
{% endcomment %}
<style>
  .bundle-banner-wrapper {
    margin-top: -1.8rem !important;
    padding: 0 !important;
  }

  .bundle-banner-wrapper img {
    width: 62%;
    height: auto;
    display: block;
    margin: 0 0 0 0 !important;
    padding: 0 !important;
    vertical-align: bottom;
  }

  /* Conserver la taille sur mobile */
  @media (max-width: 749px) {
    .bundle-banner-wrapper img {
      width: 96%;
    }
  }
</style>
<div class="bundle-banner-wrapper">
  <img 
    src="https://cdn.shopify.com/s/files/1/0868/4496/5201/files/WELCOME_KIT_bb4dce9e-8035-4d46-bb93-0f839c95d180.webp?v=1778009267" 
